{"path": "/opt/data/gsd-lawyerinc/src/agent-cards.js", "content": "/**
 * @module agent-cards
 * @description Agent discovery and capability matching for GSD v2.
 *
 * AgentCards declare what an agent CAN do (capabilities, task types,
 * platforms, cost tiers). The registry loads cards from config or
 * disk and matches them to tasks.
 *
 * Architecture:
 *   - AgentCard: immutable descriptor of one agent
 *   - AgentRegistry: collection of cards with query/match methods
 *   - matchAgent(): find the best agent for a given task
 */

// ---------------------------------------------------------------------------
// AgentCard
// ---------------------------------------------------------------------------

/**
 * @typedef {Object} AgentCardData
 * @property {string} id              - Unique slug (e.g., 'hermes-ceo', 'openclaw/main')
 * @property {string} name            - Display name
 * @property {string} platform        - 'hermes' | 'openclaw' | 'paperclip' | 'external'
 * @property {string[]} taskTypes     - Task types this agent handles (e.g., ['code', 'document'])
 * @property {string[]} capabilities  - Fine-grained capabilities (e.g., ['git', 'research', 'legal-writing'])
 * @property {string} costTier        - 'free' | 'low' | 'medium' | 'high'
 * @property {number} [maxConcurrent] - Max concurrent tasks (default: 1)
 * @property {boolean} [available]    - Whether agent is currently available (default: true)
 * @property {Object} [metadata]      - Arbitrary extra data (URLs, auth info, etc.)
 */

export class AgentCard {
  /**
   * @param {AgentCardData} data
   */
  constructor(data) {
    if (!data.id) throw new Error('AgentCard requires an id');
    if (!data.platform) throw new Error(`AgentCard "${data.id}" requires a platform`);

    this.id = data.id;
    this.name = data.name || data.id;
    this.platform = data.platform;
    this.taskTypes = Array.isArray(data.taskTypes) ? [...data.taskTypes] : [];
    this.capabilities = Array.isArray(data.capabilities) ? [...data.capabilities] : [];
    this.costTier = data.costTier || 'medium';
    this.maxConcurrent = data.maxConcurrent ?? 1;
    this.available = data.available !== false;
    this.metadata = data.metadata ? { ...data.metadata } : {};

    Object.freeze(this.taskTypes);
    Object.freeze(this.capabilities);
  }

  /**
   * Check if this agent can handle a given task type.
   * @param {string} taskType
   * @returns {boolean}
   */
  handlesType(taskType) {
    if (this.taskTypes.length === 0) return true; // wildcard — handles anything
    return this.taskTypes.includes(taskType);
  }

  /**
   * Check if this agent has a specific capability.
   * @param {string} capability
   * @returns {boolean}
   */
  hasCapability(capability) {
    return this.capabilities.includes(capability);
  }

  /**
   * Check if this agent has ALL of the given capabilities.
   * @param {string[]} required
   * @returns {boolean}
   */
  hasAllCapabilities(required) {
    return required.every(cap => this.capabilities.includes(cap));
  }

  /**
   * Check if this agent has ANY of the given capabilities.
   * @param {string[]} desired
   * @returns {boolean}
   */
  hasAnyCapability(desired) {
    if (desired.length === 0) return true;
    return desired.some(cap => this.capabilities.includes(cap));
  }

  /**
   * Score how well this agent matches a task.
   * Higher = better match.
   *
   * @param {Object} criteria
   * @param {string} criteria.taskType - Required task type
   * @param {string[]} [criteria.requiredCapabilities] - Must-have capabilities
   * @param {string[]} [criteria.preferredCapabilities] - Nice-to-have capabilities
   * @param {string} [criteria.preferredCostTier] - Preferred cost tier
   * @returns {number} Score (0 = no match, higher = better)
   */
  score(criteria) {
    // Must handle the task type
    if (!this.handlesType(criteria.taskType)) return 0;

    // Must be available
    if (!this.available) return 0;

    // Must have all required capabilities
    const required = criteria.requiredCapabilities || [];
    if (!this.hasAllCapabilities(required)) return 0;

    // Base score: 10 for matching type
    let score = 10;

    // Bonus for preferred capabilities (2 points each)
    const preferred = criteria.preferredCapabilities || [];
    for (const cap of preferred) {
      if (this.capabilities.includes(cap)) score += 2;
    }

    // Bonus for matching cost tier (3 points)
    if (criteria.preferredCostTier && this.costTier === criteria.preferredCostTier) {
      score += 3;
    }

    // Slight penalty for expensive agents when no preference stated
    const costPenalty = { free: 0, low: 0, medium: 1, high: 3 };
    if (!criteria.preferredCostTier) {
      score -= (costPenalty[this.costTier] || 0);
    }

    return score;
  }

  /**
   * Serialize to plain object.
   * @returns {AgentCardData}
   */
  toJSON() {
    return {
      id: this.id,
      name: this.name,
      platform: this.platform,
      taskTypes: [...this.taskTypes],
      capabilities: [...this.capabilities],
      costTier: this.costTier,
      maxConcurrent: this.maxConcurrent,
      available: this.available,
      metadata: { ...this.metadata },
    };
  }
}

// ---------------------------------------------------------------------------
// AgentRegistry
// ---------------------------------------------------------------------------

export class AgentRegistry {
  constructor() {
    /** @type {Map<string, AgentCard>} */
    this._agents = new Map();
  }

  /**
   * Register an agent card.
   * @param {AgentCard|AgentCardData} cardOrData
   * @returns {AgentCard}
   */
  register(cardOrData) {
    const card = cardOrData instanceof AgentCard
      ? cardOrData
      : new AgentCard(cardOrData);

    this._agents.set(card.id, card);
    return card;
  }

  /**
   * Register multiple agent cards at once.
   * @param {(AgentCard|AgentCardData)[]} cards
   * @returns {AgentCard[]}
   */
  registerAll(cards) {
    return cards.map(c => this.register(c));
  }

  /**
   * Get an agent by ID.
   * @param {string} id
   * @returns {AgentCard|undefined}
   */
  get(id) {
    return this._agents.get(id);
  }

  /**
   * Remove an agent by ID.
   * @param {string} id
   * @returns {boolean}
   */
  remove(id) {
    return this._agents.delete(id);
  }

  /**
   * Get all registered agents.
   * @returns {AgentCard[]}
   */
  all() {
    return [...this._agents.values()];
  }

  /**
   * Get agents filtered by platform.
   * @param {string} platform
   * @returns {AgentCard[]}
   */
  byPlatform(platform) {
    return this.all().filter(a => a.platform === platform);
  }

  /**
   * Get agents that can handle a specific task type.
   * @param {string} taskType
   * @returns {AgentCard[]}
   */
  byTaskType(taskType) {
    return this.all().filter(a => a.handlesType(taskType));
  }

  /**
   * Get available agents only.
   * @returns {AgentCard[]}
   */
  available() {
    return this.all().filter(a => a.available);
  }

  /**
   * Find the best agent for a task based on scoring criteria.
   *
   * @param {Object} criteria
   * @param {string} criteria.taskType
   * @param {string[]} [criteria.requiredCapabilities]
   * @param {string[]} [criteria.preferredCapabilities]
   * @param {string} [criteria.preferredCostTier]
   * @returns {AgentCard|null}
   */
  bestMatch(criteria) {
    let bestAgent = null;
    let bestScore = 0;

    for (const agent of this._agents.values()) {
      const s = agent.score(criteria);
      if (s > bestScore) {
        bestScore = s;
        bestAgent = agent;
      }
    }

    return bestAgent;
  }

  /**
   * Find all matching agents, sorted by score (best first).
   *
   * @param {Object} criteria
   * @param {string} criteria.taskType
   * @param {string[]} [criteria.requiredCapabilities]
   * @param {string[]} [criteria.preferredCapabilities]
   * @param {string} [criteria.preferredCostTier]
   * @returns {{agent: AgentCard, score: number}[]}
   */
  rankedMatches(criteria) {
    const results = [];

    for (const agent of this._agents.values()) {
      const s = agent.score(criteria);
      if (s > 0) {
        results.push({ agent, score: s });
      }
    }

    results.sort((a, b) => b.score - a.score);
    return results;
  }

  /**
   * Load registry from a config object (e.g., .planning/config.json).
   * Expects config.agents to be an array of AgentCardData or
   * config.agents to be a nested object with platform keys.
   *
   * @param {Object} config
   * @returns {AgentCard[]}
   */
  loadFromConfig(config) {
    const agents = config?.agents;
    if (!agents) return [];

    // Format 1: agents is an array of card data
    if (Array.isArray(agents)) {
      return this.registerAll(agents);
    }

    // Format 2: agents is { cards: [...] }
    if (Array.isArray(agents.cards)) {
      return this.registerAll(agents.cards);
    }

    // Format 3: agents has platform sub-keys { hermes: {...}, openclaw: {...}, ... }
    const cards = [];
    for (const [platform, platConfig] of Object.entries(agents)) {
      if (platform === 'cards') continue;
      if (typeof platConfig !== 'object' || platConfig === null) continue;

      // platConfig could be an array of agents on this platform
      if (Array.isArray(platConfig)) {
        for (const agentData of platConfig) {
          cards.push(this.register({ ...agentData, platform }));
        }
      }
      // or a single agent definition with ids, url, etc.
      else if (platConfig.ids || platConfig.url) {
        // Legacy format — skip, handled by dispatcher directly
        continue;
      }
    }

    return cards;
  }

  /**
   * Total agent count.
   * @returns {number}
   */
  get size() {
    return this._agents.size;
  }

  /**
   * Serialize all agents to JSON-safe array.
   * @returns {AgentCardData[]}
   */
  toJSON() {
    return this.all().map(a => a.toJSON());
  }

  /**
   * Clear all agents.
   */
  clear() {
    this._agents.clear();
  }
}

