{"path": "/opt/data/gsd-lawyerinc/src/contracts.js", "content": "/**
 * @module contracts
 * @description Sprint contracts for GSD v2.
 *
 * A Contract binds a Slice to its success criteria, verification gates,
 * and agent commitments. When a slice enters EXECUTE, a contract is
 * created. When all criteria are met and verified, the contract is
 * fulfilled. If criteria fail, the contract records the failure.
 *
 * Architecture:
 *   - SuccessCriterion: one measurable condition
 *   - VerificationGate: a checkpoint that must pass before advancing
 *   - Contract: ties a slice to its criteria + gates + agent assignments
 *   - ContractManager: create, evaluate, and track contracts
 */

// ---------------------------------------------------------------------------
// Enums
// ---------------------------------------------------------------------------

export const CRITERION_STATUS = Object.freeze({
  PENDING: 'pending',
  MET: 'met',
  FAILED: 'failed',
  WAIVED: 'waived',
});

export const GATE_STATUS = Object.freeze({
  PENDING: 'pending',
  PASSED: 'passed',
  FAILED: 'failed',
  SKIPPED: 'skipped',
});

export const CONTRACT_STATUS = Object.freeze({
  DRAFT: 'draft',
  ACTIVE: 'active',
  FULFILLED: 'fulfilled',
  BREACHED: 'breached',
  CANCELLED: 'cancelled',
});

// ---------------------------------------------------------------------------
// SuccessCriterion
// ---------------------------------------------------------------------------

/**
 * One measurable condition that must be true for the contract to be fulfilled.
 */
export class SuccessCriterion {
  /**
   * @param {Object} data
   * @param {string} data.id         - Unique criterion ID (e.g., 'SC-01')
   * @param {string} data.description - Human-readable description
   * @param {string} [data.verifyCmd] - Optional automated verification command
   * @param {string} [data.status]    - Current status
   * @param {string} [data.evidence]  - Proof that criterion was met
   * @param {string} [data.evaluatedAt] - ISO timestamp of last evaluation
   */
  constructor(data) {
    if (!data.id) throw new Error('SuccessCriterion requires an id');
    if (!data.description) throw new Error(`SuccessCriterion "${data.id}" requires a description`);

    this.id = data.id;
    this.description = data.description;
    this.verifyCmd = data.verifyCmd || null;
    this.status = data.status || CRITERION_STATUS.PENDING;
    this.evidence = data.evidence || null;
    this.evaluatedAt = data.evaluatedAt || null;
  }

  /** Mark as met with evidence. */
  meet(evidence) {
    this.status = CRITERION_STATUS.MET;
    this.evidence = evidence;
    this.evaluatedAt = new Date().toISOString();
  }

  /** Mark as failed with reason. */
  fail(reason) {
    this.status = CRITERION_STATUS.FAILED;
    this.evidence = reason;
    this.evaluatedAt = new Date().toISOString();
  }

  /** Waive this criterion (e.g., no longer applicable). */
  waive(reason) {
    this.status = CRITERION_STATUS.WAIVED;
    this.evidence = reason || 'Waived';
    this.evaluatedAt = new Date().toISOString();
  }

  get isMet() {
    return this.status === CRITERION_STATUS.MET || this.status === CRITERION_STATUS.WAIVED;
  }

  get isFailed() {
    return this.status === CRITERION_STATUS.FAILED;
  }

  toJSON() {
    return {
      id: this.id,
      description: this.description,
      verifyCmd: this.verifyCmd,
      status: this.status,
      evidence: this.evidence,
      evaluatedAt: this.evaluatedAt,
    };
  }
}

// ---------------------------------------------------------------------------
// VerificationGate
// ---------------------------------------------------------------------------

/**
 * A checkpoint that must pass before the slice can advance.
 * Gates are ordered — they're evaluated sequentially.
 */
export class VerificationGate {
  /**
   * @param {Object} data
   * @param {string} data.id           - Gate ID (e.g., 'VG-01')
   * @param {string} data.name         - Human-readable name
   * @param {string} data.type         - 'automated' | 'manual' | 'approval'
   * @param {string} [data.verifyCmd]  - Command to run for automated gates
   * @param {string} [data.approver]   - Who must approve (for 'approval' type)
   * @param {string[]} [data.criteriaIds] - Which criteria this gate checks
   * @param {string} [data.status]
   * @param {string} [data.result]     - Pass/fail details
   * @param {string} [data.evaluatedAt]
   */
  constructor(data) {
    if (!data.id) throw new Error('VerificationGate requires an id');
    if (!data.name) throw new Error(`VerificationGate "${data.id}" requires a name`);

    this.id = data.id;
    this.name = data.name;
    this.type = data.type || 'manual';
    this.verifyCmd = data.verifyCmd || null;
    this.approver = data.approver || null;
    this.criteriaIds = data.criteriaIds || [];
    this.status = data.status || GATE_STATUS.PENDING;
    this.result = data.result || null;
    this.evaluatedAt = data.evaluatedAt || null;
  }

  /** Pass the gate with result details. */
  pass(result) {
    this.status = GATE_STATUS.PASSED;
    this.result = result || 'Passed';
    this.evaluatedAt = new Date().toISOString();
  }

  /** Fail the gate with reason. */
  fail(reason) {
    this.status = GATE_STATUS.FAILED;
    this.result = reason;
    this.evaluatedAt = new Date().toISOString();
  }

  /** Skip the gate (e.g., not applicable). */
  skip(reason) {
    this.status = GATE_STATUS.SKIPPED;
    this.result = reason || 'Skipped';
    this.evaluatedAt = new Date().toISOString();
  }

  get isPassed() {
    return this.status === GATE_STATUS.PASSED || this.status === GATE_STATUS.SKIPPED;
  }

  toJSON() {
    return {
      id: this.id,
      name: this.name,
      type: this.type,
      verifyCmd: this.verifyCmd,
      approver: this.approver,
      criteriaIds: [...this.criteriaIds],
      status: this.status,
      result: this.result,
      evaluatedAt: this.evaluatedAt,
    };
  }
}

// ---------------------------------------------------------------------------
// Contract
// ---------------------------------------------------------------------------

/**
 * A sprint contract ties a Slice to its success criteria, verification gates,
 * and agent commitments.
 */
export class Contract {
  /**
   * @param {Object} data
   * @param {string} data.id            - Contract ID (e.g., 'C-M001-S01')
   * @param {string} data.sliceId       - The slice this contract belongs to
   * @param {string} [data.milestoneId] - Parent milestone
   * @param {(SuccessCriterion|Object)[]} [data.criteria] - Success criteria
   * @param {(VerificationGate|Object)[]} [data.gates]    - Verification gates
   * @param {Object[]} [data.agentCommitments] - Which agents committed to which tasks
   * @param {string} [data.status]
   * @param {string} [data.createdAt]
   * @param {string} [data.fulfilledAt]
   */
  constructor(data) {
    if (!data.id) throw new Error('Contract requires an id');
    if (!data.sliceId) throw new Error(`Contract "${data.id}" requires a sliceId`);

    this.id = data.id;
    this.sliceId = data.sliceId;
    this.milestoneId = data.milestoneId || null;
    this.status = data.status || CONTRACT_STATUS.DRAFT;
    this.createdAt = data.createdAt || new Date().toISOString();
    this.fulfilledAt = data.fulfilledAt || null;

    // Hydrate criteria
    this.criteria = (data.criteria || []).map(c =>
      c instanceof SuccessCriterion ? c : new SuccessCriterion(c)
    );

    // Hydrate gates
    this.gates = (data.gates || []).map(g =>
      g instanceof VerificationGate ? g : new VerificationGate(g)
    );

    // Agent commitments: [{ agentId, taskIds, accepted, completedAt }]
    this.agentCommitments = (data.agentCommitments || []).map(ac => ({
      agentId: ac.agentId,
      taskIds: ac.taskIds || [],
      accepted: ac.accepted !== false,
      completedAt: ac.completedAt || null,
    }));
  }

  /** Activate the contract (slice enters EXECUTE). */
  activate() {
    if (this.status !== CONTRACT_STATUS.DRAFT) {
      throw new Error(`Cannot activate contract "${this.id}" — status is ${this.status}`);
    }
    this.status = CONTRACT_STATUS.ACTIVE;
  }

  /**
   * Evaluate all criteria and gates. Returns summary.
   * @returns {{ allCriteriaMet: boolean, allGatesPassed: boolean, fulfilled: boolean, summary: Object }}
   */
  evaluate() {
    const criteriaResults = {
      total: this.criteria.length,
      met: this.criteria.filter(c => c.isMet).length,
      failed: this.criteria.filter(c => c.isFailed).length,
      pending: this.criteria.filter(c => c.status === CRITERION_STATUS.PENDING).length,
    };

    const gateResults = {
      total: this.gates.length,
      passed: this.gates.filter(g => g.isPassed).length,
      failed: this.gates.filter(g => g.status === GATE_STATUS.FAILED).length,
      pending: this.gates.filter(g => g.status === GATE_STATUS.PENDING).length,
    };

    const allCriteriaMet = criteriaResults.met === criteriaResults.total;
    const allGatesPassed = gateResults.passed === gateResults.total;
    const fulfilled = allCriteriaMet && allGatesPassed;

    return { allCriteriaMet, allGatesPassed, fulfilled, criteria: criteriaResults, gates: gateResults };
  }

  /**
   * Try to fulfill the contract. Returns true if all criteria and gates pass.
   * @returns {boolean}
   */
  tryFulfill() {
    if (this.status !== CONTRACT_STATUS.ACTIVE) return false;

    const { fulfilled } = this.evaluate();
    if (fulfilled) {
      this.status = CONTRACT_STATUS.FULFILLED;
      this.fulfilledAt = new Date().toISOString();
      return true;
    }
    return false;
  }

  /**
   * Breach the contract (unrecoverable failure).
   * @param {string} reason
   */
  breach(reason) {
    this.status = CONTRACT_STATUS.BREACHED;
    this.fulfilledAt = new Date().toISOString();
    // Store breach reason on a meta field
    this._breachReason = reason;
  }

  /** Cancel the contract. */
  cancel() {
    this.status = CONTRACT_STATUS.CANCELLED;
  }

  /**
   * Get a specific criterion by ID.
   * @param {string} id
   * @returns {SuccessCriterion|undefined}
   */
  getCriterion(id) {
    return this.criteria.find(c => c.id === id);
  }

  /**
   * Get a specific gate by ID.
   * @param {string} id
   * @returns {VerificationGate|undefined}
   */
  getGate(id) {
    return this.gates.find(g => g.id === id);
  }

  toJSON() {
    return {
      id: this.id,
      sliceId: this.sliceId,
      milestoneId: this.milestoneId,
      status: this.status,
      createdAt: this.createdAt,
      fulfilledAt: this.fulfilledAt,
      criteria: this.criteria.map(c => c.toJSON()),
      gates: this.gates.map(g => g.toJSON()),
      agentCommitments: this.agentCommitments.map(ac => ({ ...ac })),
    };
  }
}

// ---------------------------------------------------------------------------
// ContractManager
// ---------------------------------------------------------------------------

/**
 * Manages contracts across a project. Stores them in memory and
 * provides lookup/evaluation helpers.
 */
export class ContractManager {
  constructor() {
    /** @type {Map<string, Contract>} */
    this._contracts = new Map();
  }

  /**
   * Create a contract for a slice.
   *
   * @param {Object} opts
   * @param {string} opts.sliceId
   * @param {string} [opts.milestoneId]
   * @param {Object[]} opts.criteria - Array of { id, description, verifyCmd? }
   * @param {Object[]} [opts.gates] - Array of gate data
   * @param {Object[]} [opts.agentCommitments] - Array of { agentId, taskIds }
   * @returns {Contract}
   */
  create(opts) {
    const id = `C-${opts.milestoneId || 'X'}-${opts.sliceId}`;
    const contract = new Contract({
      id,
      sliceId: opts.sliceId,
      milestoneId: opts.milestoneId,
      criteria: opts.criteria,
      gates: opts.gates || [],
      agentCommitments: opts.agentCommitments || [],
    });

    this._contracts.set(id, contract);
    return contract;
  }

  /**
   * Get a contract by ID.
   * @param {string} id
   * @returns {Contract|undefined}
   */
  get(id) {
    return this._contracts.get(id);
  }

  /**
   * Find contract for a slice.
   * @param {string} sliceId
   * @returns {Contract|undefined}
   */
  forSlice(sliceId) {
    for (const contract of this._contracts.values()) {
      if (contract.sliceId === sliceId) return contract;
    }
    return undefined;
  }

  /**
   * Get all contracts.
   * @returns {Contract[]}
   */
  all() {
    return [...this._contracts.values()];
  }

  /**
   * Get contracts by status.
   * @param {string} status
   * @returns {Contract[]}
   */
  byStatus(status) {
    return this.all().filter(c => c.status === status);
  }

  /**
   * Evaluate all active contracts and return a summary.
   * @returns {{ active: number, fulfilled: number, breached: number, details: Object[] }}
   */
  evaluateAll() {
    const details = [];
    let fulfilled = 0;
    let breached = 0;

    for (const contract of this.byStatus(CONTRACT_STATUS.ACTIVE)) {
      const eval_ = contract.evaluate();
      details.push({ contractId: contract.id, sliceId: contract.sliceId, ...eval_ });

      if (eval_.fulfilled) {
        contract.tryFulfill();
        fulfilled++;
      }
    }

    return {
      active: this.byStatus(CONTRACT_STATUS.ACTIVE).length,
      fulfilled,
      breached: this.byStatus(CONTRACT_STATUS.BREACHED).length,
      details,
    };
  }

  /**
   * Total count.
   * @returns {number}
   */
  get size() {
    return this._contracts.size;
  }

  /**
   * Serialize all contracts.
   * @returns {Object[]}
   */
  toJSON() {
    return this.all().map(c => c.toJSON());
  }

  /**
   * Load contracts from serialized data.
   * @param {Object[]} data
   */
  loadAll(data) {
    for (const d of data) {
      const contract = new Contract(d);
      this._contracts.set(contract.id, contract);
    }
  }

  /** Clear all contracts. */
  clear() {
    this._contracts.clear();
  }
}

// ---------------------------------------------------------------------------
// Helper: create a contract from a Slice object
// ---------------------------------------------------------------------------

/**
 * Generate a contract from a Slice's "must be true" criteria and tasks.
 *
 * @param {import('./hierarchy.js').Slice} slice
 * @param {Object} [options]
 * @param {string} [options.milestoneId]
 * @param {boolean} [options.autoGate=true] - Auto-create a verification gate
 * @returns {Contract}
 */
export function contractFromSlice(slice, options = {}) {
  const milestoneId = options.milestoneId || null;

  // Generate criteria from slice metadata or tasks
  const criteria = [];
  if (slice.metadata?.mustBeTrue) {
    const mustBeTrue = Array.isArray(slice.metadata.mustBeTrue)
      ? slice.metadata.mustBeTrue
      : [slice.metadata.mustBeTrue];

    mustBeTrue.forEach((desc, i) => {
      criteria.push({ id: `SC-${String(i + 1).padStart(2, '0')}`, description: desc });
    });
  }

  // If no explicit criteria, derive from tasks
  if (criteria.length === 0 && slice.tasks) {
    for (const task of slice.tasks) {
      if (task.verify) {
        criteria.push({
          id: `SC-${task.id}`,
          description: `Task ${task.id}: ${task.verify}`,
        });
      }
    }
  }

  // Auto-create verification gate
  const gates = [];
  if (options.autoGate !== false && criteria.length > 0) {
    gates.push({
      id: `VG-${slice.id}-final`,
      name: `Final verification for ${slice.id}`,
      type: 'manual',
      criteriaIds: criteria.map(c => c.id),
    });
  }

  // Agent commitments from task assignments
  const commitmentMap = new Map();
  if (slice.tasks) {
    for (const task of slice.tasks) {
      if (task.assignee) {
        if (!commitmentMap.has(task.assignee)) {
          commitmentMap.set(task.assignee, []);
        }
        commitmentMap.get(task.assignee).push(task.id);
      }
    }
  }

  const agentCommitments = [...commitmentMap.entries()].map(([agentId, taskIds]) => ({
    agentId,
    taskIds,
  }));

  return new Contract({
    id: `C-${milestoneId || 'X'}-${slice.id}`,
    sliceId: slice.id,
    milestoneId,
    criteria,
    gates,
    agentCommitments,
  });
}
"}

{"path": "/opt/data/gsd-lawyerinc/src/costs.js", "content": "/**
 * @module costs
 * @description Token usage and cost tracking for GSD v2.
 *
 * Tracks costs per task, per agent, per slice, per project.
 * Aggregates usage data for budget awareness and reporting.
 *
 * Architecture:
 *   - CostEntry: one usage event (a task dispatch, an API call, etc.)
 *   - CostTracker: accumulates entries and provides rollups
 *   - Budget: optional spending caps with alerts
 */

// ---------------------------------------------------------------------------
// CostEntry
// ---------------------------------------------------------------------------

/**
 * @typedef {Object} CostEntryData
 * @property {string} [id]          - Unique entry ID (auto-generated if omitted)
 * @property {string} taskId        - Which task this cost is for
 * @property {string} agentId       - Which agent incurred this cost
 * @property {string} [sliceId]     - Parent slice
 * @property {string} [milestoneId] - Parent milestone
 * @property {string} [projectId]   - Parent project
 * @property {number} inputTokens   - Input/prompt tokens
 * @property {number} outputTokens  - Output/completion tokens
 * @property {number} [totalTokens] - Override total (if not input+output)
 * @property {string} model         - Model used (e.g., 'gpt-5.4', 'claude-sonnet-4-6')
 * @property {string} [provider]    - Provider (e.g., 'openrouter', 'openai')
 * @property {number} [costUsd]     - Dollar cost (if known)
 * @property {string} [timestamp]   - ISO timestamp
 * @property {Object} [metadata]    - Extra data
 */

let _entrySeq = 0;

export class CostEntry {
  /**
   * @param {CostEntryData} data
   */
  constructor(data) {
    this.id = data.id || `cost-${++_entrySeq}-${Date.now()}`;
    this.taskId = data.taskId || 'unknown';
    this.agentId = data.agentId || 'unknown';
    this.sliceId = data.sliceId || null;
    this.milestoneId = data.milestoneId || null;
    this.projectId = data.projectId || null;
    this.inputTokens = data.inputTokens || 0;
    this.outputTokens = data.outputTokens || 0;
    this.totalTokens = data.totalTokens ?? (this.inputTokens + this.outputTokens);
    this.model = data.model || 'unknown';
    this.provider = data.provider || null;
    this.costUsd = data.costUsd ?? null;
    this.timestamp = data.timestamp || new Date().toISOString();
    this.metadata = data.metadata || {};
  }

  toJSON() {
    return {
      id: this.id,
      taskId: this.taskId,
      agentId: this.agentId,
      sliceId: this.sliceId,
      milestoneId: this.milestoneId,
      projectId: this.projectId,
      inputTokens: this.inputTokens,
      outputTokens: this.outputTokens,
      totalTokens: this.totalTokens,
      model: this.model,
      provider: this.provider,
      costUsd: this.costUsd,
      timestamp: this.timestamp,
      metadata: { ...this.metadata },
    };
  }
}

// ---------------------------------------------------------------------------
// Model pricing table (approx $/1M tokens — updated as needed)
// ---------------------------------------------------------------------------

const MODEL_PRICING = {
  'gpt-5.4':              { input: 2.50, output: 10.00 },
  'gpt-4.1':              { input: 2.00, output: 8.00 },
  'gpt-4.1-mini':         { input: 0.40, output: 1.60 },
  'gpt-4.1-nano':         { input: 0.10, output: 0.40 },
  'claude-sonnet-4-6':  { input: 3.00, output: 15.00 },
  'claude-opus-4-6':    { input: 15.00, output: 75.00 },
  'claude-haiku-3.5':     { input: 0.80, output: 4.00 },
  'o3':                   { input: 10.00, output: 40.00 },
  'o4-mini':              { input: 1.10, output: 4.40 },
};

/**
 * Estimate USD cost from token counts and model.
 * Returns null if model not in pricing table.
 *
 * @param {string} model
 * @param {number} inputTokens
 * @param {number} outputTokens
 * @returns {number|null}
 */
export function estimateCost(model, inputTokens, outputTokens) {
  const pricing = MODEL_PRICING[model];
  if (!pricing) return null;

  const inputCost = (inputTokens / 1_000_000) * pricing.input;
  const outputCost = (outputTokens / 1_000_000) * pricing.output;
  return Math.round((inputCost + outputCost) * 1_000_000) / 1_000_000; // 6 decimal places
}

/**
 * Add or update model pricing.
 * @param {string} model
 * @param {number} inputPer1M
 * @param {number} outputPer1M
 */
export function setPricing(model, inputPer1M, outputPer1M) {
  MODEL_PRICING[model] = { input: inputPer1M, output: outputPer1M };
}

// ---------------------------------------------------------------------------
// CostTracker
// ---------------------------------------------------------------------------

export class CostTracker {
  constructor() {
    /** @type {CostEntry[]} */
    this._entries = [];
  }

  /**
   * Record a cost entry.
   * Auto-estimates USD cost if not provided and model is known.
   *
   * @param {CostEntryData} data
   * @returns {CostEntry}
   */
  record(data) {
    const entry = new CostEntry(data);

    // Auto-estimate cost if not provided
    if (entry.costUsd === null) {
      entry.costUsd = estimateCost(entry.model, entry.inputTokens, entry.outputTokens);
    }

    this._entries.push(entry);
    return entry;
  }

  /**
   * Get all entries.
   * @returns {CostEntry[]}
   */
  all() {
    return [...this._entries];
  }

  /**
   * Filter entries by criteria.
   * @param {Object} filter
   * @param {string} [filter.taskId]
   * @param {string} [filter.agentId]
   * @param {string} [filter.sliceId]
   * @param {string} [filter.milestoneId]
   * @param {string} [filter.projectId]
   * @param {string} [filter.model]
   * @returns {CostEntry[]}
   */
  filter(filter) {
    return this._entries.filter(e => {
      if (filter.taskId && e.taskId !== filter.taskId) return false;
      if (filter.agentId && e.agentId !== filter.agentId) return false;
      if (filter.sliceId && e.sliceId !== filter.sliceId) return false;
      if (filter.milestoneId && e.milestoneId !== filter.milestoneId) return false;
      if (filter.projectId && e.projectId !== filter.projectId) return false;
      if (filter.model && e.model !== filter.model) return false;
      return true;
    });
  }

  /**
   * Aggregate token counts and costs.
   * @param {CostEntry[]} [entries] - Entries to aggregate (default: all)
   * @returns {{ inputTokens: number, outputTokens: number, totalTokens: number, costUsd: number, count: number }}
   */
  aggregate(entries) {
    const items = entries || this._entries;
    const result = { inputTokens: 0, outputTokens: 0, totalTokens: 0, costUsd: 0, count: items.length };

    for (const e of items) {
      result.inputTokens += e.inputTokens;
      result.outputTokens += e.outputTokens;
      result.totalTokens += e.totalTokens;
      result.costUsd += e.costUsd || 0;
    }

    result.costUsd = Math.round(result.costUsd * 1_000_000) / 1_000_000;
    return result;
  }

  /**
   * Get cost breakdown by agent.
   * @returns {Map<string, { inputTokens: number, outputTokens: number, totalTokens: number, costUsd: number, count: number }>}
   */
  byAgent() {
    const map = new Map();
    for (const e of this._entries) {
      if (!map.has(e.agentId)) {
        map.set(e.agentId, { inputTokens: 0, outputTokens: 0, totalTokens: 0, costUsd: 0, count: 0 });
      }
      const agg = map.get(e.agentId);
      agg.inputTokens += e.inputTokens;
      agg.outputTokens += e.outputTokens;
      agg.totalTokens += e.totalTokens;
      agg.costUsd += e.costUsd || 0;
      agg.count++;
    }
    return map;
  }

  /**
   * Get cost breakdown by slice.
   * @returns {Map<string, { inputTokens: number, outputTokens: number, totalTokens: number, costUsd: number, count: number }>}
   */
  bySlice() {
    const map = new Map();
    for (const e of this._entries) {
      const key = e.sliceId || 'unassigned';
      if (!map.has(key)) {
        map.set(key, { inputTokens: 0, outputTokens: 0, totalTokens: 0, costUsd: 0, count: 0 });
      }
      const agg = map.get(key);
      agg.inputTokens += e.inputTokens;
      agg.outputTokens += e.outputTokens;
      agg.totalTokens += e.totalTokens;
      agg.costUsd += e.costUsd || 0;
      agg.count++;
    }
    return map;
  }

  /**
   * Get cost breakdown by model.
   * @returns {Map<string, { inputTokens: number, outputTokens: number, totalTokens: number, costUsd: number, count: number }>}
   */
  byModel() {
    const map = new Map();
    for (const e of this._entries) {
      if (!map.has(e.model)) {
        map.set(e.model, { inputTokens: 0, outputTokens: 0, totalTokens: 0, costUsd: 0, count: 0 });
      }
      const agg = map.get(e.model);
      agg.inputTokens += e.inputTokens;
      agg.outputTokens += e.outputTokens;
      agg.totalTokens += e.totalTokens;
      agg.costUsd += e.costUsd || 0;
      agg.count++;
    }
    return map;
  }

  /**
   * Total entry count.
   * @returns {number}
   */
  get size() {
    return this._entries.length;
  }

  /**
   * Serialize all entries.
   * @returns {Object[]}
   */
  toJSON() {
    return this._entries.map(e => e.toJSON());
  }

  /**
   * Load entries from serialized data.
   * @param {Object[]} data
   */
  loadAll(data) {
    for (const d of data) {
      this._entries.push(new CostEntry(d));
    }
  }

  /** Clear all entries. */
  clear() {
    this._entries = [];
  }
}

// ---------------------------------------------------------------------------
// Budget
// ---------------------------------------------------------------------------

/**
 * Optional spending caps with alerts.
 */
export class Budget {
  /**
   * @param {Object} data
   * @param {number} [data.maxUsd]         - Total USD cap
   * @param {number} [data.maxTokens]      - Total token cap
   * @param {number} [data.warnAtPercent]   - Warn when this % of budget is used (default: 80)
   * @param {Object} [data.perAgent]        - Per-agent caps: { agentId: { maxUsd, maxTokens } }
   * @param {Object} [data.perSlice]        - Per-slice caps
   */
  constructor(data = {}) {
    this.maxUsd = data.maxUsd ?? Infinity;
    this.maxTokens = data.maxTokens ?? Infinity;
    this.warnAtPercent = data.warnAtPercent ?? 80;
    this.perAgent = data.perAgent || {};
    this.perSlice = data.perSlice || {};
  }

  /**
   * Check budget status against a cost tracker.
   *
   * @param {CostTracker} tracker
   * @returns {{ ok: boolean, warning: boolean, exceeded: boolean, usage: Object, alerts: string[] }}
   */
  check(tracker) {
    const totals = tracker.aggregate();
    const alerts = [];
    let warning = false;
    let exceeded = false;

    // Global USD check
    if (totals.costUsd >= this.maxUsd) {
      exceeded = true;
      alerts.push(`Budget exceeded: $${totals.costUsd.toFixed(4)} / $${this.maxUsd.toFixed(2)}`);
    } else if (this.maxUsd < Infinity && (totals.costUsd / this.maxUsd) * 100 >= this.warnAtPercent) {
      warning = true;
      alerts.push(`Budget warning: $${totals.costUsd.toFixed(4)} / $${this.maxUsd.toFixed(2)} (${((totals.costUsd / this.maxUsd) * 100).toFixed(1)}%)`);
    }

    // Global token check
    if (totals.totalTokens >= this.maxTokens) {
      exceeded = true;
      alerts.push(`Token cap exceeded: ${totals.totalTokens.toLocaleString()} / ${this.maxTokens.toLocaleString()}`);
    } else if (this.maxTokens < Infinity && (totals.totalTokens / this.maxTokens) * 100 >= this.warnAtPercent) {
      warning = true;
      alerts.push(`Token warning: ${totals.totalTokens.toLocaleString()} / ${this.maxTokens.toLocaleString()}`);
    }

    // Per-agent checks
    const byAgent = tracker.byAgent();
    for (const [agentId, caps] of Object.entries(this.perAgent)) {
      const agentUsage = byAgent.get(agentId);
      if (!agentUsage) continue;

      if (caps.maxUsd && agentUsage.costUsd >= caps.maxUsd) {
        exceeded = true;
        alerts.push(`Agent "${agentId}" budget exceeded: $${agentUsage.costUsd.toFixed(4)} / $${caps.maxUsd.toFixed(2)}`);
      }
      if (caps.maxTokens && agentUsage.totalTokens >= caps.maxTokens) {
        exceeded = true;
        alerts.push(`Agent "${agentId}" token cap exceeded: ${agentUsage.totalTokens.toLocaleString()} / ${caps.maxTokens.toLocaleString()}`);
      }
    }

    return {
      ok: !exceeded && !warning,
      warning,
      exceeded,
      usage: totals,
      alerts,
    };
  }

  toJSON() {
    return {
      maxUsd: this.maxUsd === Infinity ? null : this.maxUsd,
      maxTokens: this.maxTokens === Infinity ? null : this.maxTokens,
      warnAtPercent: this.warnAtPercent,
      perAgent: { ...this.perAgent },
      perSlice: { ...this.perSlice },
    };
  }
}
