// ─── AgentCard-Aware Routing ────────────────────────────────────────────────────

/** @type {AgentRegistry|null} Lazily-initialized registry */
let _registry = null;

/** @type {CostTracker|null} Lazily-initialized cost tracker */
let _costTracker = null;

/**
 * Get or create the global agent registry.
 * Loads default Lawyer Inc agents, then merges any config-defined agents.
 *
 * @param {Object} [config] - Optional config with agents field
 * @returns {AgentRegistry}
 */
export function getRegistry(config) {
  if (!_registry) {
    _registry = createDefaultRegistry();
  }
  if (config?.agents) {
    _registry.loadFromConfig(config);
  }
  return _registry;
}

/**
 * Replace the global registry (for testing or config reload).
 * @param {AgentRegistry} registry
 */
export function setRegistry(registry) {
  _registry = registry;
}

/**
 * Get or create the global cost tracker.
 * @returns {CostTracker}
 */
export function getCostTracker() {
  if (!_costTracker) {
    _costTracker = new CostTracker();
  }
  return _costTracker;
}

/**
 * Replace the global cost tracker (for testing).
 * @param {CostTracker} tracker
 */
export function setCostTracker(tracker) {
  _costTracker = tracker;
}

/**
 * Smart dispatch: use AgentCards to find the best agent for a task,
 * then dispatch to the appropriate platform.
 *
 * Falls back to the original detectPlatform() logic if no AgentCard match.
 *
 * @param {Object} task
 * @param {Object} [options]
 * @param {boolean} [options.dryRun=false]
 * @param {AgentRegistry} [options.registry]
 * @returns {Promise<DispatchResult>}
 */
export async function smartDispatch(task, options = {}) {
  const config = await getConfig();
  const registry = options.registry || getRegistry(config);

  // Try AgentCard matching
  const { agent, explicit } = matchAgent(task, registry);

  if (agent) {
    // Override task assignee with matched agent
    const dispatchTask_ = { ...task };
    if (!explicit) {
      dispatchTask_.assignee = agent.id;
    }

    // Route based on agent's platform
    const result = await dispatchToplatform(dispatchTask_, agent.platform, options);

    // Annotate result with agent card info
    result.agentCard = agent.id;
    result.matchType = explicit ? 'explicit' : 'capability';

    return result;
  }

  // Fallback to legacy routing
  return dispatchTask(task, options);
}

/**
 * Dispatch to a specific platform.
 * @param {Object} task
 * @param {string} platform
 * @param {Object} [options]
 * @returns {Promise<DispatchResult>}
 */
async function dispatchToplatform(task, platform, options = {}) {
  if (options.dryRun) {
    return {
      taskId: task.id,
      assignee: task.assignee,
      platform,
      success: true,
      status: null,
      response: { dryRun: true, wouldDispatchTo: platform },
      error: null,
    };
  }

  switch (platform) {
    case 'openclaw':
      return dispatchToOpenClaw(task);
    case 'hermes':
      return dispatchToHermes(task);
    case 'paperclip':
      return dispatchToPaperclip(task);
    default:
      return {
        taskId: task.id,
        assignee: task.assignee,
        platform,
        success: false,
        status: null,
        response: null,
        error: `Unknown platform "${platform}" for agent "${task.assignee}"`,
      };
  }
}"}

