{"path": "/opt/data/gsd-lawyerinc/src/lifecycle.js", "content": "/**
 * @module lifecycle
 * @description Slice lifecycle runner for GSD v2.
 *
 * Drives a Slice through its phases:
 *   DISCUSS → RESEARCH → PLAN → APPROVE → EXECUTE → VERIFY → COMPLETE
 *
 * Each phase transition has:
 *   - Entry conditions (what must be true to enter)
 *   - Actions (what happens in this phase)
 *   - Exit conditions (what must be true to leave)
 *   - Hooks (callbacks for external systems — MC sync, Telegram, etc.)
 *
 * The runner is event-driven and checkpoint-aware:
 *   - Emits events on phase transitions
 *   - Saves checkpoints after each phase change
 *   - Can resume from a checkpoint after a crash
 */

import { SLICE_PHASE, TASK_STATUS } from './hierarchy.js';
import { advancePhase } from './state.js';

// ---------------------------------------------------------------------------
// Phase transition rules
// ---------------------------------------------------------------------------

/**
 * @typedef {Object} PhaseRule
 * @property {string} phase        - The SLICE_PHASE value
 * @property {string} next         - Next phase (or null for terminal)
 * @property {function} canEnter   - (slice, ctx) => boolean
 * @property {function} canExit    - (slice, ctx) => boolean
 * @property {boolean} requiresApproval - Whether this phase needs human approval to exit
 */

const PHASE_RULES = {
  [SLICE_PHASE.DISCUSS]: {
    phase: SLICE_PHASE.DISCUSS,
    next: SLICE_PHASE.RESEARCH,
    canEnter: () => true,
    canExit: (slice, ctx) => {
      // Need at least a context or decision recorded
      return !!slice.context || ctx?.discussComplete === true;
    },
    requiresApproval: false,
  },

  [SLICE_PHASE.RESEARCH]: {
    phase: SLICE_PHASE.RESEARCH,
    next: SLICE_PHASE.PLAN,
    canEnter: () => true,
    canExit: (slice, ctx) => {
      return !!slice.research || ctx?.researchComplete === true;
    },
    requiresApproval: false,
  },

  [SLICE_PHASE.PLAN]: {
    phase: SLICE_PHASE.PLAN,
    next: SLICE_PHASE.APPROVE,
    canEnter: () => true,
    canExit: (slice) => {
      // Need at least one task defined
      return slice.tasks && slice.tasks.length > 0;
    },
    requiresApproval: false,
  },

  [SLICE_PHASE.APPROVE]: {
    phase: SLICE_PHASE.APPROVE,
    next: SLICE_PHASE.EXECUTE,
    canEnter: (slice) => slice.tasks && slice.tasks.length > 0,
    canExit: (slice, ctx) => {
      return ctx?.approved === true;
    },
    requiresApproval: true,
  },

  [SLICE_PHASE.EXECUTE]: {
    phase: SLICE_PHASE.EXECUTE,
    next: SLICE_PHASE.VERIFY,
    canEnter: (slice, ctx) => ctx?.approved === true || ctx?.skipApproval === true,
    canExit: (slice) => {
      // All tasks must be completed or failed
      if (!slice.tasks || slice.tasks.length === 0) return false;
      return slice.tasks.every(t =>
        t.status === TASK_STATUS.COMPLETED || t.status === TASK_STATUS.FAILED
      );
    },
    requiresApproval: false,
  },

  [SLICE_PHASE.VERIFY]: {
    phase: SLICE_PHASE.VERIFY,
    next: SLICE_PHASE.COMPLETE,
    canEnter: (slice) => {
      return slice.tasks && slice.tasks.every(t =>
        t.status === TASK_STATUS.COMPLETED || t.status === TASK_STATUS.FAILED
      );
    },
    canExit: (slice, ctx) => {
      // Contract must be fulfilled, or verification manually approved
      return ctx?.verified === true || ctx?.contractFulfilled === true;
    },
    requiresApproval: false,
  },

  [SLICE_PHASE.COMPLETE]: {
    phase: SLICE_PHASE.COMPLETE,
    next: null,
    canEnter: (slice, ctx) => ctx?.verified === true || ctx?.contractFulfilled === true,
    canExit: () => false, // Terminal
    requiresApproval: false,
  },
};

/**
 * Get the rule for a phase.
 * @param {string} phase
 * @returns {PhaseRule|undefined}
 */
export function getPhaseRule(phase) {
  return PHASE_RULES[phase];
}

/**
 * Get all phase rules in order.
 * @returns {PhaseRule[]}
 */
export function getPhaseOrder() {
  return [
    PHASE_RULES[SLICE_PHASE.DISCUSS],
    PHASE_RULES[SLICE_PHASE.RESEARCH],
    PHASE_RULES[SLICE_PHASE.PLAN],
    PHASE_RULES[SLICE_PHASE.APPROVE],
    PHASE_RULES[SLICE_PHASE.EXECUTE],
    PHASE_RULES[SLICE_PHASE.VERIFY],
    PHASE_RULES[SLICE_PHASE.COMPLETE],
  ];
}

// ---------------------------------------------------------------------------
// Lifecycle events
// ---------------------------------------------------------------------------

/**
 * @typedef {Object} LifecycleEvent
 * @property {string} type         - Event type
 * @property {string} sliceId      - Which slice
 * @property {string} [fromPhase]  - Previous phase
 * @property {string} [toPhase]    - New phase
 * @property {string} [taskId]     - Related task (for task events)
 * @property {Object} [data]       - Additional event data
 * @property {string} timestamp    - ISO timestamp
 */

// ---------------------------------------------------------------------------
// SliceRunner
// ---------------------------------------------------------------------------

/**
 * Drives a single slice through its lifecycle.
 */
export class SliceRunner {
  /**
   * @param {Object} opts
   * @param {import('./hierarchy.js').Slice} opts.slice - The slice to run
   * @param {string} [opts.milestoneId] - Parent milestone
   * @param {string} [opts.projectDir] - Project directory for disk ops
   * @param {Object} [opts.hooks] - Lifecycle hooks
   * @param {function} [opts.hooks.onPhaseEnter]  - (event) => Promise<void>
   * @param {function} [opts.hooks.onPhaseExit]   - (event) => Promise<void>
   * @param {function} [opts.hooks.onTaskUpdate]   - (event) => Promise<void>
   * @param {function} [opts.hooks.onApprovalNeeded] - (event) => Promise<boolean>
   * @param {function} [opts.hooks.onError]        - (event) => Promise<void>
   * @param {function} [opts.hooks.onCheckpoint]   - (checkpoint) => Promise<void>
   * @param {import('./contracts.js').Contract} [opts.contract] - Sprint contract
   * @param {import('./costs.js').CostTracker} [opts.costTracker] - Cost tracker
   */
  constructor(opts) {
    this.slice = opts.slice;
    this.milestoneId = opts.milestoneId || null;
    this.projectDir = opts.projectDir || '.';
    this.hooks = opts.hooks || {};
    this.contract = opts.contract || null;
    this.costTracker = opts.costTracker || null;

    /** @type {Object} Mutable context passed to phase rules */
    this.ctx = {};

    /** @type {LifecycleEvent[]} Event log */
    this.events = [];

    /** @type {boolean} Whether the runner is paused (waiting for approval, etc.) */
    this.paused = false;

    /** @type {string|null} Why paused */
    this.pauseReason = null;

    /** @type {boolean} Whether the runner has been aborted */
    this.aborted = false;
  }

  // ── Event helpers ────────────────────────────────────────────────────

  _emit(type, data = {}) {
    const event = {
      type,
      sliceId: this.slice.id,
      milestoneId: this.milestoneId,
      timestamp: new Date().toISOString(),
      ...data,
    };
    this.events.push(event);
    return event;
  }

  async _callHook(hookName, event) {
    const hook = this.hooks[hookName];
    if (hook) {
      try {
        return await hook(event);
      } catch (err) {
        const errorEvent = this._emit('hook_error', {
          hook: hookName,
          error: err.message,
        });
        if (this.hooks.onError) {
          await this.hooks.onError(errorEvent);
        }
      }
    }
    return undefined;
  }

  // ── Phase transitions ───────────────────────────────────────────────

  /**
   * Check if the slice can advance to the next phase.
   * @returns {{ canAdvance: boolean, currentPhase: string, nextPhase: string|null, reason: string|null }}
   */
  canAdvance() {
    const rule = PHASE_RULES[this.slice.phase];
    if (!rule) {
      return { canAdvance: false, currentPhase: this.slice.phase, nextPhase: null, reason: 'Unknown phase' };
    }

    if (!rule.next) {
      return { canAdvance: false, currentPhase: this.slice.phase, nextPhase: null, reason: 'Terminal phase' };
    }

    if (!rule.canExit(this.slice, this.ctx)) {
      return { canAdvance: false, currentPhase: this.slice.phase, nextPhase: rule.next, reason: 'Exit conditions not met' };
    }

    const nextRule = PHASE_RULES[rule.next];
    if (nextRule && !nextRule.canEnter(this.slice, this.ctx)) {
      return { canAdvance: false, currentPhase: this.slice.phase, nextPhase: rule.next, reason: 'Entry conditions not met for next phase' };
    }

    return { canAdvance: true, currentPhase: this.slice.phase, nextPhase: rule.next, reason: null };
  }

  /**
   * Advance the slice to the next phase.
   * @returns {Promise<{ advanced: boolean, fromPhase: string, toPhase: string|null, reason: string|null }>}
   */
  async advance() {
    if (this.aborted) {
      return { advanced: false, fromPhase: this.slice.phase, toPhase: null, reason: 'Runner aborted' };
    }

    const check = this.canAdvance();
    if (!check.canAdvance) {
      return { advanced: false, fromPhase: check.currentPhase, toPhase: check.nextPhase, reason: check.reason };
    }

    const fromPhase = this.slice.phase;
    const toPhase = check.nextPhase;

    // Exit current phase
    const exitEvent = this._emit('phase_exit', { fromPhase, toPhase });
    await this._callHook('onPhaseExit', exitEvent);

    // Transition
    this.slice.phase = toPhase;

    // Enter new phase
    const enterEvent = this._emit('phase_enter', { fromPhase, toPhase });
    await this._callHook('onPhaseEnter', enterEvent);

    // Checkpoint
    await this._checkpoint();

    // If new phase requires approval, pause
    const newRule = PHASE_RULES[toPhase];
    if (newRule?.requiresApproval) {
      this.paused = true;
      this.pauseReason = `Waiting for approval in ${toPhase} phase`;

      const approvalEvent = this._emit('approval_needed', { phase: toPhase });
      const approved = await this._callHook('onApprovalNeeded', approvalEvent);

      if (approved === true) {
        this.ctx.approved = true;
        this.paused = false;
        this.pauseReason = null;
      }
    }

    return { advanced: true, fromPhase, toPhase, reason: null };
  }

  /**
   * Force-set the slice to a specific phase (for recovery).
   * @param {string} phase
   */
  setPhase(phase) {
    this.slice.phase = phase;
    this._emit('phase_force_set', { toPhase: phase });
  }

  // ── Context management ──────────────────────────────────────────────

  /**
   * Set a context value (affects phase rule evaluation).
   * @param {string} key
   * @param {*} value
   */
  setContext(key, value) {
    this.ctx[key] = value;
  }

  /**
   * Approve the current phase (for APPROVE phase).
   */
  approve() {
    this.ctx.approved = true;
    this.paused = false;
    this.pauseReason = null;
    this._emit('approved', { phase: this.slice.phase });
  }

  /**
   * Mark verification as complete.
   */
  verify() {
    this.ctx.verified = true;
    this._emit('verified', { phase: this.slice.phase });
  }

  /**
   * Mark a task as completed.
   * @param {string} taskId
   * @param {Object} [data] - Additional data (summary, cost, etc.)
   */
  completeTask(taskId, data = {}) {
    const task = this.slice.tasks?.find(t => t.id === taskId);
    if (!task) return;

    task.status = TASK_STATUS.COMPLETED;
    task.completedAt = new Date().toISOString();
    if (data.summary) task.summary = data.summary;

    // Track cost if provided
    if (data.cost && this.costTracker) {
      this.costTracker.record({
        taskId,
        agentId: task.assignee || 'unknown',
        sliceId: this.slice.id,
        milestoneId: this.milestoneId,
        ...data.cost,
      });
    }

    const event = this._emit('task_completed', { taskId, data });
    this._callHook('onTaskUpdate', event);
  }

  /**
   * Mark a task as failed.
   * @param {string} taskId
   * @param {string} reason
   */
  failTask(taskId, reason) {
    const task = this.slice.tasks?.find(t => t.id === taskId);
    if (!task) return;

    task.status = TASK_STATUS.FAILED;
    task.summary = reason;

    const event = this._emit('task_failed', { taskId, reason });
    this._callHook('onTaskUpdate', event);
  }

  // ── Run loop ────────────────────────────────────────────────────────

  /**
   * Run the lifecycle until it can't advance further.
   * Returns when paused (needs approval), completed, or stuck.
   *
   * @returns {Promise<{ finalPhase: string, eventsEmitted: number, reason: string }>}
   */
  async run() {
    let advances = 0;
    const maxAdvances = 10; // Safety valve

    while (advances < maxAdvances) {
      if (this.aborted) {
        return { finalPhase: this.slice.phase, eventsEmitted: this.events.length, reason: 'aborted' };
      }

      if (this.paused) {
        return { finalPhase: this.slice.phase, eventsEmitted: this.events.length, reason: `paused: ${this.pauseReason}` };
      }

      const result = await this.advance();
      if (!result.advanced) {
        const reason = this.slice.phase === SLICE_PHASE.COMPLETE ? 'completed' : `stuck: ${result.reason}`;
        return { finalPhase: this.slice.phase, eventsEmitted: this.events.length, reason };
      }

      advances++;
    }

    return { finalPhase: this.slice.phase, eventsEmitted: this.events.length, reason: 'max_advances_reached' };
  }

  /**
   * Abort the runner.
   * @param {string} reason
   */
  abort(reason) {
    this.aborted = true;
    this._emit('aborted', { reason });
  }

  // ── Checkpoint ──────────────────────────────────────────────────────

  /**
   * Get a checkpoint of the current state (for crash recovery).
   * @returns {Object}
   */
  getCheckpoint() {
    return {
      sliceId: this.slice.id,
      milestoneId: this.milestoneId,
      phase: this.slice.phase,
      ctx: { ...this.ctx },
      paused: this.paused,
      pauseReason: this.pauseReason,
      aborted: this.aborted,
      taskStatuses: (this.slice.tasks || []).map(t => ({
        id: t.id,
        status: t.status,
        completedAt: t.completedAt || null,
      })),
      eventCount: this.events.length,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Restore from a checkpoint.
   * @param {Object} checkpoint
   */
  restoreFromCheckpoint(checkpoint) {
    if (checkpoint.phase) this.slice.phase = checkpoint.phase;
    if (checkpoint.ctx) this.ctx = { ...checkpoint.ctx };
    if (checkpoint.paused !== undefined) this.paused = checkpoint.paused;
    if (checkpoint.pauseReason !== undefined) this.pauseReason = checkpoint.pauseReason;
    if (checkpoint.aborted !== undefined) this.aborted = checkpoint.aborted;

    // Restore task statuses
    if (checkpoint.taskStatuses && this.slice.tasks) {
      for (const ts of checkpoint.taskStatuses) {
        const task = this.slice.tasks.find(t => t.id === ts.id);
        if (task) {
          task.status = ts.status;
          if (ts.completedAt) task.completedAt = ts.completedAt;
        }
      }
    }

    this._emit('restored_from_checkpoint', { checkpoint_timestamp: checkpoint.timestamp });
  }

  async _checkpoint() {
    const cp = this.getCheckpoint();
    await this._callHook('onCheckpoint', cp);
    return cp;
  }
}

// ---------------------------------------------------------------------------
// MilestoneRunner
// ---------------------------------------------------------------------------

/**
 * Drives all slices in a milestone sequentially.
 */
export class MilestoneRunner {
  /**
   * @param {Object} opts
   * @param {import('./hierarchy.js').Milestone} opts.milestone
   * @param {string} [opts.projectDir]
   * @param {Object} [opts.hooks] - Same hooks as SliceRunner, applied to each slice
   * @param {import('./costs.js').CostTracker} [opts.costTracker]
   * @param {import('./contracts.js').ContractManager} [opts.contractManager]
   */
  constructor(opts) {
    this.milestone = opts.milestone;
    this.projectDir = opts.projectDir || '.';
    this.hooks = opts.hooks || {};
    this.costTracker = opts.costTracker || null;
    this.contractManager = opts.contractManager || null;

    /** @type {Map<string, SliceRunner>} */
    this.sliceRunners = new Map();

    /** @type {LifecycleEvent[]} */
    this.events = [];
  }

  /**
   * Create a SliceRunner for a slice.
   * @param {import('./hierarchy.js').Slice} slice
   * @returns {SliceRunner}
   */
  _createSliceRunner(slice) {
    const contract = this.contractManager
      ? this.contractManager.forSlice(slice.id)
      : null;

    const runner = new SliceRunner({
      slice,
      milestoneId: this.milestone.id,
      projectDir: this.projectDir,
      hooks: this.hooks,
      contract,
      costTracker: this.costTracker,
    });

    this.sliceRunners.set(slice.id, runner);
    return runner;
  }

  /**
   * Get the runner for a specific slice.
   * @param {string} sliceId
   * @returns {SliceRunner|undefined}
   */
  getSliceRunner(sliceId) {
    return this.sliceRunners.get(sliceId);
  }

  /**
   * Run all slices in order. Stops if a slice is paused or stuck.
   * @returns {Promise<{ completedSlices: number, totalSlices: number, stoppedAt: string|null, reason: string }>}
   */
  async run() {
    const slices = this.milestone.slices || [];
    let completedSlices = 0;

    for (const slice of slices) {
      const runner = this._createSliceRunner(slice);
      const result = await runner.run();

      this.events.push(...runner.events);

      if (result.reason === 'completed') {
        completedSlices++;
      } else {
        // Slice is paused or stuck — stop milestone
        return {
          completedSlices,
          totalSlices: slices.length,
          stoppedAt: slice.id,
          reason: result.reason,
        };
      }
    }

    return {
      completedSlices,
      totalSlices: slices.length,
      stoppedAt: null,
      reason: completedSlices === slices.length ? 'all_complete' : 'partial',
    };
  }

  /**
   * Get checkpoint for all slices.
   * @returns {Object}
   */
  getCheckpoint() {
    const sliceCheckpoints = {};
    for (const [id, runner] of this.sliceRunners) {
      sliceCheckpoints[id] = runner.getCheckpoint();
    }

    return {
      milestoneId: this.milestone.id,
      sliceCheckpoints,
      eventCount: this.events.length,
      timestamp: new Date().toISOString(),
    };
  }
}
"}

