 * @module checkpoint
 * @description Crash recovery for GSD v2 lifecycle.
 *
 * Persists runner state to disk after every phase transition.
 * On restart, loads the latest checkpoint and resumes the runner
 * from where it left off.
 *
 * Storage: .planning/checkpoints/{sliceId}.json
 */

import { readFile, writeFile, mkdir } from 'node:fs/promises';
import { join, dirname } from 'node:path';
import { existsSync } from 'node:fs';

// ---------------------------------------------------------------------------
// Checkpoint persistence
// ---------------------------------------------------------------------------

const DEFAULT_CHECKPOINT_DIR = '.planning/checkpoints';

/**
 * Save a checkpoint to disk.
 *
 * @param {Object} checkpoint - Checkpoint data from SliceRunner.getCheckpoint()
 * @param {Object} [opts]
 * @param {string} [opts.dir] - Checkpoint directory (default: .planning/checkpoints)
 * @param {string} [opts.projectDir] - Project root directory
 * @returns {Promise<string>} Path where checkpoint was saved
 */
export async function saveCheckpoint(checkpoint, opts = {}) {
  const baseDir = opts.projectDir || '.';
  const cpDir = join(baseDir, opts.dir || DEFAULT_CHECKPOINT_DIR);

  // Ensure directory exists
  await mkdir(cpDir, { recursive: true });

  const filename = `${checkpoint.sliceId || checkpoint.milestoneId || 'unknown'}.json`;
  const filepath = join(cpDir, filename);

  const data = {
    ...checkpoint,
    _savedAt: new Date().toISOString(),
    _version: 2,
  };

  await writeFile(filepath, JSON.stringify(data, null, 2), 'utf-8');
  return filepath;
}

/**
 * Load a checkpoint from disk.
 *
 * @param {string} sliceId - Slice ID to load checkpoint for
 * @param {Object} [opts]
 * @param {string} [opts.dir] - Checkpoint directory
 * @param {string} [opts.projectDir] - Project root
 * @returns {Promise<Object|null>} Checkpoint data, or null if not found
 */
export async function loadCheckpoint(sliceId, opts = {}) {
  const baseDir = opts.projectDir || '.';
  const cpDir = join(baseDir, opts.dir || DEFAULT_CHECKPOINT_DIR);
  const filepath = join(cpDir, `${sliceId}.json`);

  try {
    const raw = await readFile(filepath, 'utf-8');
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

/**
 * Check if a checkpoint exists for a slice.
 *
 * @param {string} sliceId
 * @param {Object} [opts]
 * @returns {boolean}
 */
export function hasCheckpoint(sliceId, opts = {}) {
  const baseDir = opts.projectDir || '.';
  const cpDir = join(baseDir, opts.dir || DEFAULT_CHECKPOINT_DIR);
  const filepath = join(cpDir, `${sliceId}.json`);
  return existsSync(filepath);
}

/**
 * Delete a checkpoint (e.g., after slice completion).
 *
 * @param {string} sliceId
 * @param {Object} [opts]
 * @returns {Promise<boolean>}
 */
export async function deleteCheckpoint(sliceId, opts = {}) {
  const baseDir = opts.projectDir || '.';
  const cpDir = join(baseDir, opts.dir || DEFAULT_CHECKPOINT_DIR);
  const filepath = join(cpDir, `${sliceId}.json`);

  try {
    const { unlink } = await import('node:fs/promises');
    await unlink(filepath);
    return true;
  } catch {
    return false;
  }
}

/**
 * List all available checkpoints.
 *
 * @param {Object} [opts]
 * @returns {Promise<{sliceId: string, timestamp: string, phase: string}[]>}
 */
export async function listCheckpoints(opts = {}) {
  const baseDir = opts.projectDir || '.';
  const cpDir = join(baseDir, opts.dir || DEFAULT_CHECKPOINT_DIR);

  try {
    const { readdir } = await import('node:fs/promises');
    const files = await readdir(cpDir);
    const checkpoints = [];

    for (const file of files) {
      if (!file.endsWith('.json')) continue;

      try {
        const raw = await readFile(join(cpDir, file), 'utf-8');
        const cp = JSON.parse(raw);
        checkpoints.push({
          sliceId: cp.sliceId || file.replace('.json', ''),
          timestamp: cp.timestamp || cp._savedAt,
          phase: cp.phase || 'unknown',
          paused: cp.paused || false,
          aborted: cp.aborted || false,
        });
      } catch {
        // Corrupted checkpoint — skip
      }
    }

    return checkpoints;
  } catch {
    return [];
  }
}

// ---------------------------------------------------------------------------
// Checkpoint hook factory
// ---------------------------------------------------------------------------

/**
 * Create lifecycle hooks that auto-save checkpoints.
 * Pass the returned hooks into SliceRunner or MilestoneRunner.
 *
 * @param {Object} [opts]
 * @param {string} [opts.projectDir] - Project root
 * @param {string} [opts.dir] - Checkpoint directory
 * @param {function} [opts.onSaved] - Callback after checkpoint saved: (filepath, checkpoint) => void
 * @returns {Object} hooks object with onCheckpoint, onPhaseEnter, onPhaseExit
 */
export function createCheckpointHooks(opts = {}) {
  return {
    onCheckpoint: async (checkpoint) => {
      const filepath = await saveCheckpoint(checkpoint, opts);
      if (opts.onSaved) {
        opts.onSaved(filepath, checkpoint);
      }
    },
  };
}

// ---------------------------------------------------------------------------
// Recovery: resume a SliceRunner from checkpoint
// ---------------------------------------------------------------------------

/**
 * Resume a SliceRunner from a saved checkpoint.
 *
 * @param {import('./lifecycle.js').SliceRunner} runner - A fresh SliceRunner
 * @param {string} sliceId - Slice to resume
 * @param {Object} [opts] - Same as loadCheckpoint opts
 * @returns {Promise<{resumed: boolean, checkpoint: Object|null}>}
 */
export async function resumeFromCheckpoint(runner, sliceId, opts = {}) {
  const checkpoint = await loadCheckpoint(sliceId, opts);
  if (!checkpoint) {
    return { resumed: false, checkpoint: null };
  }

  runner.restoreFromCheckpoint(checkpoint);
  return { resumed: true, checkpoint };
}
"}

