 * @returns {Promise<{success: boolean, error: string|null}>}
 */
export async function syncContractToMC(contract) {
  const eval_ = contract.evaluate();
  const summary = [
    `Contract ${contract.id} — ${contract.status.toUpperCase()}`,
    `Criteria: ${eval_.criteria.met}/${eval_.criteria.total} met`,
    `Gates: ${eval_.gates.passed}/${eval_.gates.total} passed`,
    contract.fulfilledAt ? `Fulfilled: ${contract.fulfilledAt}` : '',
  ].filter(Boolean).join('\n');

  // Find the MC task for this slice
  const mapping = _taskMappings.get(contract.sliceId);
  if (!mapping) {
    return { success: false, error: `No MC mapping for slice "${contract.sliceId}"` };
  }

  const result = await mcFetch(`/api/tasks/${mapping.mcTaskId}`, {
    method: 'PATCH',
    body: JSON.stringify({
      tags: ['gsd-managed', `contract-${contract.status}`],
      description: summary,
    }),
  });

  return {
    success: result.ok,
    error: result.ok ? null : `MC contract sync failed (${result.status})`,
  };
}

/**
 * Sync cost summary to MC as a task tag/field update.
 *
 * @param {import('./costs.js').CostTracker} tracker
 * @param {string} sliceId - Which slice's costs to sync
 * @returns {Promise<{success: boolean, error: string|null}>}
 */
export async function syncCostsToMC(tracker, sliceId) {
  const entries = tracker.filter({ sliceId });
  const totals = tracker.aggregate(entries);

  const mapping = _taskMappings.get(sliceId);
  if (!mapping) {
    return { success: false, error: `No MC mapping for slice "${sliceId}"` };
  }

  const costTag = `cost-$${totals.costUsd.toFixed(4)}`;
  const tokenTag = `tokens-${totals.totalTokens}`;

  const result = await mcFetch(`/api/tasks/${mapping.mcTaskId}`, {
    method: 'PATCH',
    body: JSON.stringify({
      tags: ['gsd-managed', costTag, tokenTag],
    }),
  });

  return {
    success: result.ok,
    error: result.ok ? null : `MC cost sync failed (${result.status})`,
  };
}

